#include <stdio.h>
#include <stdint.h>
const long long MOD = 1000000007LL;
long long modpow(long long a, long long e) {
    long long r = 1;
    while (e) {
        if (e & 1) r = r * a % MOD;
        a = a * a % MOD;
        e >>= 1;
    }
    return r;
}
int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        long long N; scanf("%lld", &N);
        long long invN = modpow(N % MOD, MOD-2);
        long long nMod = N % MOD;
        long long n1 = (N + 1) % MOD;
        long long twoN1 = (2%MOD * nMod % MOD + 1) % MOD;
        long long inv2 = (MOD + 1) / 2; // 500000004
        long long inv6 = modpow(6, MOD-2);
        long long S = nMod * n1 % MOD * inv2 % MOD; // N(N+1)/2
        long long S2 = nMod * n1 % MOD * twoN1 % MOD * inv6 % MOD; // N(N+1)(2N+1)/6
        long long numerator = (S * S % MOD - S2 + MOD) % MOD;
        long long ans = numerator * invN % MOD;
        printf("%lld\n", ans);
    }
    return 0;
}

