    static final long MOD = 1_000_000_007L;
    static long modPow(long a, long e) {
        long r = 1L;
        while (e > 0) {
            if ((e & 1) == 1) r = (r * a) % MOD;
            a = (a * a) % MOD;
            e >>= 1;
        }
        return r;
    }
